using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }

    [Required, MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public int Status { get; set; }

    public DateTime ShippedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }

    [Required, MaxLength(200)]
    public string RecipientName { get; set; } = string.Empty;

    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;

    // Owner (customer) who can track this shipment
    public string? CustomerId { get; set; }
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null)
    {
        var query = db.Shipments.AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
        {
            query = query.Where(s => s.Status == (int)status);
        }

        return await query
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        return shipment is null ? null : ToDto(shipment);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = (int)dto.Status,
            ShippedDate = DateTime.UtcNow,
            EstimatedDelivery = dto.EstimatedDelivery,
            RecipientName = dto.RecipientName,
            Description = dto.Description
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    public async Task<ShipmentDto> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");

        shipment.Status = (int)newStatus;
        if (newStatus == ShipmentStatus.Delivered)
            shipment.ActualDelivery = DateTime.UtcNow;

        await db.SaveChangesAsync();
        return ToDto(shipment);
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        Description = s.Description
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}

using Microsoft.AspNetCore.Authorization;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        // Dispatchers: list all shipments
        group.MapGet("/", [Authorize] async (string? status, IShipmentService service) =>
        {
            var shipments = await service.GetShipmentsAsync(status);
            return Results.Ok(shipments);
        });

        // Dispatchers: get shipment by id
        group.MapGet("/{id:int}", [Authorize] async (int id, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByIdAsync(id);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Customers: track by tracking number (no auth required for public tracking)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Dispatchers: create shipment
        group.MapPost("/", [Authorize] async (ShipmentDto dto, IShipmentService service) =>
        {
            var created = await service.CreateShipmentAsync(dto);
            return Results.Created($"api/shipments/{created.Id}", created);
        });

        // Dispatchers: update status
        group.MapPut("/{id:int}/status", [Authorize] async (int id, ShipmentStatus newStatus, IShipmentService service) =>
        {
            var updated = await service.UpdateShipmentStatusAsync(id, newStatus);
            return Results.Ok(updated);
        });
    }
}

