@page "/shipments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject ShipmentTracker.Client.Services.IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h1>📦 Shipments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Filter by status:</label>
        <select class="form-select" @bind="selectedStatus" @bind:after="LoadShipments">
            <option value="">All</option>
            @foreach (var status in Enum.GetValues<ShipmentTracker.Client.Models.ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Origin</label>
                    <input class="form-control" @bind="newShipment.Origin" placeholder="e.g. New York, NY" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Destination</label>
                    <input class="form-control" @bind="newShipment.Destination" placeholder="e.g. London, UK" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Recipient Name</label>
                    <input class="form-control" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Estimated Delivery</label>
                    <input class="form-control" type="date" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-12">
                    <label class="form-label">Description</label>
                    <input class="form-control" @bind="newShipment.Description" placeholder="Package contents or notes" />
                </div>
                <div class="col-12">
                    <button class="btn btn-primary me-2" @onclick="CreateShipment" disabled="@isCreating">
                        @(isCreating ? "Creating..." : "Create")
                    </button>
                    <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p class="text-muted">No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in shipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.RecipientName</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                        <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@((int)shipment.Status)"
                                    @onchange="(e) => UpdateStatus(shipment.Id, e)">
                                @foreach (var status in Enum.GetValues<ShipmentTracker.Client.Models.ShipmentStatus>())
                                {
                                    <option value="@((int)status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentTracker.Client.Models.ShipmentDto>? shipments;
    private string selectedStatus = "";
    private bool showCreateForm;
    private bool isCreating;
    private ShipmentTracker.Client.Models.ShipmentDto newShipment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetShipmentsAsync(
            string.IsNullOrEmpty(selectedStatus) ? null : selectedStatus);
    }

    private void ShowCreateForm()
    {
        newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        try
        {
            await ShipmentService.CreateShipmentAsync(newShipment);
            showCreateForm = false;
            await LoadShipments();
        }
        finally
        {
            isCreating = false;
        }
    }

    private async Task UpdateStatus(int shipmentId, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusValue))
        {
            var newStatus = (ShipmentTracker.Client.Models.ShipmentStatus)statusValue;
            await ShipmentService.UpdateShipmentStatusAsync(shipmentId, newStatus);
            await LoadShipments();
        }
    }

    private static string GetStatusBadgeClass(ShipmentTracker.Client.Models.ShipmentStatus status) => status switch
    {
        ShipmentTracker.Client.Models.ShipmentStatus.Delivered => "bg-success",
        ShipmentTracker.Client.Models.ShipmentStatus.InTransit => "bg-primary",
        ShipmentTracker.Client.Models.ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentTracker.Client.Models.ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentTracker.Client.Models.ShipmentStatus.Returned => "bg-danger",
        ShipmentTracker.Client.Models.ShipmentStatus.Pending => "bg-secondary",
        ShipmentTracker.Client.Models.ShipmentStatus.PickedUp => "bg-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@inject ShipmentTracker.Client.Services.IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>📋 Track Your Shipment</h1>
<p class="text-muted">Enter your tracking number to check your shipment status and estimated delivery.</p>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown"
                   placeholder="e.g. SHP-20260525-12345" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isSearching">
                @(isSearching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number <code>@searchedNumber</code>. Please check the number and try again.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span><strong>Tracking:</strong> <code>@shipment.TrackingNumber</code></span>
            <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <span class="fw-bold text-primary">@shipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")</span>
                            }
                            else
                            {
                                <span class="text-muted">Not available</span>
                            }
                        </dd>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Delivered On</dt>
                            <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>
            @if (!string.IsNullOrEmpty(shipment.Description))
            {
                <p class="text-muted mt-2"><strong>Notes:</strong> @shipment.Description</p>
            }
        </div>
    </div>

    <!-- Visual status timeline -->
    <div class="mt-4">
        <h5>Shipment Progress</h5>
        <div class="progress" style="height: 30px;">
            <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                 role="progressbar"
                 style="width: @GetProgressPercentage(shipment.Status)%"
                 aria-valuenow="@GetProgressPercentage(shipment.Status)"
                 aria-valuemin="0" aria-valuemax="100">
                @shipment.Status
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentTracker.Client.Models.ShipmentDto? shipment;
